const store = $getWorkflowStaticData('global');
if (!store.sessions) store.sessions = {};

const body = $input.first().json.body ?? $input.first().json;
const sessionId = body.session_id ?? 'default';

const allTurns = store.sessions[sessionId] ?? [];

// Return last 5 turns in chronological order
const recentTurns = allTurns.slice(-5);

// Extract known contacts (names mentioned alongside action words)
const knownContacts = {};
allTurns.forEach(turn => {
  const matches = (turn.transcript ?? '').match(/(?:call|meet|email|with|for)\s+([A-Z][a-z]+)/g);
  if (matches) {
    matches.forEach(m => {
      const name = m.split(' ').pop();
      knownContacts[name] = (knownContacts[name] ?? 0) + 1;
    });
  }
});

return [{ json: { recent_turns: recentTurns, known_contacts: knownContacts, preferences: {} } }];
